    activeModifiers: Set<ModifierKey>,
    modifierStates: Map<ModifierKey, ModifierState>,
    onCopy: () -> Unit,
    onPaste: () -> Unit,
    onCancel: () -> Unit,
    onModifierClick: (ModifierKey) -> Unit,
    onSpecialKeyClick: (SpecialKey) -> Unit,
    modifier: Modifier = Modifier
) {
