                    icon = Icons.Default.ContentCopy,
                    contentDescription = stringResource(R.string.terminal_copy),
                    onClick = onCopy
                )
                AccessoryIconButton(
                    icon = Icons.Default.Close,
                    contentDescription = stringResource(R.string.terminal_cancel_selection),
                    onClick = onCancel
                )
            }

            AccessoryDivider()

            ModifierChip(
                label = "CTRL",
                state = modifierStates[ModifierKey.CTRL] ?: ModifierState.Inactive,
                isActive = ModifierKey.CTRL in activeModifiers,
                onClick = { onModifierClick(ModifierKey.CTRL) }
