            ModifierChip(
                label = "ALT",
                state = modifierStates[ModifierKey.ALT] ?: ModifierState.Inactive,
                isActive = ModifierKey.ALT in activeModifiers,
                onClick = { onModifierClick(ModifierKey.ALT) }
